def _get_selinux_context_fallback(self, path):
    """Get SELinux context using fallback methods when libselinux-python is not available."""
    context = self.selinux_initial_context()
    # Try to use getenforce to get current context
    getfcon = self.get_bin_path('getfcon')
    if getfcon is not None:
        try:
            (rc, stdout, stderr) = self.run_command([getfcon, to_native(path)])
            if rc == 0:
                # getenforce returns context in the format: user:role:type:level
                ctx_str = stdout.strip()
                if ctx_str:
                    context = ctx_str.split(':', 3)
                    return context
        except Exception:
            pass
    return context

def _set_selinux_context_fallback(self, path, context):
    """Set SELinux context using fallback methods when libselinux-python is not available."""
    # Try to use semanage to set context
    chcon = self.get_bin_path('chcon')
    if chcon is not None:
        context_str = ':'.join(context) if isinstance(context, (list, tuple)) else context
        try:
            (rc, stdout, stderr) = self.run_command([chcon, context_str, to_native(path)])
            return rc == 0
        except Exception:
            pass
